/**
 * FARMACLUB — LOGO E IDENTIDADE VISUAL
 * Inclua este arquivo em todos os módulos:
 * <script src="farmaclub_logo.js"></script>
 * Depois use: FARMACLUB_LOGO.img() para inserir a logo
 */
window.FARMACLUB_LOGO = {
  base64: "data:image/png;base64,",
  
  // Cores oficiais extraídas da logo
  cores: {
    verde:      "#3BAA35",  // Farma (texto verde)
    azul:       "#1A5FA8",  // Club (texto azul)
    verdeClaro: "#6CC04A",  // folha / degradê verde
    azulClaro:  "#4A9FD4",  // degradê azul cápsula
    vermelho:   "#E03A3A",  // metade vermelha da cápsula
    branco:     "#FFFFFF",
    cinzaClaro: "#F4F4F2",  // fundo dos sistemas
  },

  // Retorna tag <img> pronta para usar
  img: function(altura, classe) {
    return '<img src="' + this.base64 + '" style="height:' + (altura||40) + 'px;width:auto;display:block" class="' + (classe||'') + '" alt="FarmaClub">';
  },

  // Retorna tag <img> para fundo escuro (logo tem fundo branco — usar com cuidado)
  imgBranco: function(altura) {
    return '<img src="' + this.base64 + '" style="height:' + (altura||40) + 'px;width:auto;display:block;filter:brightness(0) invert(1)" alt="FarmaClub">';
  }
};
